window.onload = init;
// Response Jobs array object
var jobs = [];
// Total Results
var total_result = document.getElementById('total_results');
// Job result wrapper card
var job_card = document.getElementById("jobs_wrapper")
// Error message 
var error = document.getElementById('error')
// search keyword
var searchKeyword = document.getElementById('search_keywords');
// onLoad call function
function init() {

    // Path Params
    const params = new URLSearchParams(window.location.search);
    // Role
    const role = params.get("role");
    // company
    const location = params.get("location");
    // Load the JSON data files here
    const endpoint = './assets/json/data.json';
    // Create httprequest object
    var xhr = new XMLHttpRequest()
    // open the connection;
    xhr.open('GET', endpoint, true);
    // response type of JSON data
    xhr.responseType = 'json';
    // onload with the open connection
    // xhr.onload = function () {
    xhr.onload = function () {
        searchKeyword.innerHTML = 
        `
        <h4>Search keywords</h4>
        <p>${role} , ${location}</p>
        `
        // Check the xhr response status
        if (xhr.status === 200) {
            // Store the response in res 
            const res = xhr.response;
            // / Filter OR condition to satisfy either of the searched words
            jobs = res.jobs.filter(job => job.role === role || job.location === location)
            // Count result
            total_result.innerHTML = jobs.length;
            // check if there is no matching result
            if (jobs.length > 0) {
                job_card.innerHTML = "";
                // content
                jobs.forEach(job => {
                    // Jobs cards
                    job_card.innerHTML += `
        <a href="job.html?job_id=${job.id}" style="color:inherit">
<div class="job_card">
<i class="fa-regular fa-star icon"></i>
              <div class="logo">
                <img src="./assets/img/company/${job.logo}" alt="" />
              </div>
                <div class="job_details">
                <h3 class="">${job.role}</h3>
                <h4 class="company">${job.company}</h4>
                <div class="location_type">
                  <span class="badge">${job.location}</span>
                  <span class="badge1">${job.type}</span>
                  <p class="description">${job.description}
                  </p>
                  <p class="ago">${job.posted}</p>
                </div>
              </div>
              </div>
              </a>
            `;

                });
            } else {
                // 
                error.innerHTML = "No Results Found.. Try to search with  other Keyword"
                // Give me the random jobs
                jobs = res.jobs;
            }
        } else {
            error.innerHTML = "Connection Error. Try again later...."
            // console.log("this is connect error")
        }
    };
    xhr.send(null); // Close the connect to NULL

}